SELECT AVG(bmi) AS avg_bmi
FROM patients
WHERE sex = 'Female' AND dthstrk = 'Yes';

SELECT AVG(bmi) AS avg_bmi
FROM patients
WHERE dthstrk = 'Yes' AND smoker = 'Yes';

SELECT * 
FROM patients
WHERE patid = '0';

SELECT height 
FROM patients 
WHERE patid = '0';

SELECT AVG(ccscore) AS average_ccscore, AVG(bmi) AS average_bmi
FROM patients
WHERE dthstrk = 'Yes' AND smoker = 'Yes' AND bmi > 25;
